PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?senateMajorityLabel ?houseMajorityLabel WHERE {
  {
    SELECT(SAMPLE(?partyLabel) AS ?senateMajorityLabel) WHERE {
      wd:Q75150501 wdt:P527 ?part .
      ?part wdt:P102 ?party ; wdt:P1114 ?seats .
      ?party rdfs:label ?partyLabel .
      FILTER(LANG(?partyLabel) = "en")
    }
    ORDER BY DESC(?seats)
    LIMIT 1
  }
  {
    SELECT(SAMPLE(?partyLabel) AS ?houseMajorityLabel) WHERE {
      wd:Q75150586 wdt:P527 ?part .
      ?part wdt:P102 ?party ; wdt:P1114 ?seats .
      ?party rdfs:label ?partyLabel .
      FILTER(LANG(?partyLabel) = "en")
    }
    ORDER BY DESC(?seats)
    LIMIT 1
  }
}

